{"code": "import json

# Load ETF symbols from file
with open('/tmp/nyse_arca_etfs.json', 'r') as f:
    etf_symbols = json.load(f)

# Create simple structure for batch processing
batch_size = 50
batch_info = []

for i in range(0, len(etf_symbols), batch_size):
    batch = etf_symbols[i:i+batch_size]
    query_parts = []

    for symbol in batch:
        query_parts.append('SELECT \'' + symbol + '\' as Symbol FROM \'' + symbol + '\' WHERE Date >= \'2015-01-01\' AND Date <= \'2015-12-31\' AND \'Adj Close\' > 200 LIMIT 1')

    batch_info.append({
        'start_idx': i,
        'size': len(batch),
        'symbols': batch
    })

print('__RESULT__:')
print(json.dumps({
    'total_etfs': len(etf_symbols),
    'num_batches': len(batch_info),
    'sample_batch': batch_info[0]
}))"}
